import { useEffect, useId, useRef, useState, type KeyboardEvent } from "react"
import type { PreviewKind } from "../../canvas/types"
import { usePrismaticInteraction } from "../../hooks/usePrismaticStore"
import { useImagePanelSize } from "../panels/ImagePanel"
import { imageComponentMetrics } from "../../workspace/imageLayout"
import { BUTTON_TEXT_LG, ButtonEllipseVisual } from "./Button"

const TEXT_SM =
  "font-['PP_Neue_Montreal',system-ui,sans-serif] text-[12px] leading-[1.1] tracking-[-0.24px] lowercase"

export type ImageComponentProps = {
  src: string
  kind: PreviewKind
  fileName: string
  sizeKB: number
  /** Required when used outside `ImagePanel`. Inside `ImagePanel`, size follows the panel. */
  size?: number
  onReplace: (file: File) => void
}

export function ImageComponent({
  src,
  kind,
  fileName,
  sizeKB,
  size,
  onReplace,
}: ImageComponentProps) {
  const inputId = useId()
  const inputRef = useRef<HTMLInputElement>(null)
  const interactionEnabled = usePrismaticInteraction()
  const [isActive, setIsActive] = useState(false)
  const panelSide = useImagePanelSize()
  const resolvedSize = panelSide ?? size
  if (resolvedSize == null || resolvedSize <= 0) {
    throw new Error("ImageComponent requires `size` or an ImagePanel parent")
  }
  const metrics = imageComponentMetrics(resolvedSize)
  const showActive = interactionEnabled && isActive

  useEffect(() => {
    if (!interactionEnabled) setIsActive(false)
  }, [interactionEnabled])

  const shortName =
    fileName.length > 42 ? `${fileName.slice(0, 39)}…` : fileName

  const openPicker = () => inputRef.current?.click()

  const onKeyDown = (e: KeyboardEvent) => {
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault()
      openPicker()
    }
  }

  return (
    <div
      data-prismatic-interactive=""
      className="group relative shrink-0 cursor-pointer rounded-[500px] outline-none [corner-shape:round]"
      style={{ width: resolvedSize, height: resolvedSize }}
      role="button"
      tabIndex={0}
      aria-label="Replace source image or video"
      onClick={openPicker}
      onKeyDown={onKeyDown}
      onMouseEnter={() => interactionEnabled && setIsActive(true)}
      onMouseLeave={() => setIsActive(false)}
      onFocus={() => interactionEnabled && setIsActive(true)}
      onBlur={() => setIsActive(false)}
    >
      <div
        className="absolute inset-0 overflow-hidden rounded-full transition-[filter] duration-200 [corner-shape:round]"
        style={{ filter: `blur(${showActive ? 0 : metrics.blur}px)` }}
      >
        {kind === "video" ? (
          <video
            src={src}
            muted
            loop
            playsInline
            autoPlay
            className="block size-full max-w-none object-cover"
          />
        ) : (
          <img
            alt=""
            src={src}
            className="block size-full max-w-none object-cover"
          />
        )}
      </div>
      <div
        className="absolute inset-0 flex flex-col items-center justify-center"
        style={{
          paddingLeft: metrics.paddingX,
          paddingRight: metrics.paddingX,
          paddingTop: metrics.paddingY,
          paddingBottom: metrics.paddingY,
        }}
      >
        <div
          className={[
            "prismatic-border-accent prismatic-bg-image-meta prismatic-corners-inner flex w-full max-w-[274px] flex-col justify-center border border-solid pl-[18px] pr-[12px] prismatic-text-muted backdrop-blur-[10px] transition-[background-color,border-color,color] duration-200 group-hover:border-transparent group-hover:prismatic-bg-image-meta-hover group-hover:prismatic-text-primary",
            metrics.showFileSize ? "gap-2 py-3" : "py-2.5",
          ].join(" ")}
          style={{
            width: metrics.metaWidth,
            height: metrics.metaHeight,
          }}
        >
          <p
            className={[
              "line-clamp-2",
              metrics.compactFilename ? "max-h-[28px]" : "max-h-[44px]",
              metrics.compactFilename ? TEXT_SM : BUTTON_TEXT_LG,
            ].join(" ")}
          >
            {shortName}
          </p>
          {metrics.showFileSize && (
            <p className={TEXT_SM}>{sizeKB} kb</p>
          )}
        </div>
        <ButtonEllipseVisual
          active={showActive}
          width={metrics.metaWidth}
          height={metrics.replaceHeight}
        >
          replace
        </ButtonEllipseVisual>
      </div>
      <input
        ref={inputRef}
        id={inputId}
        type="file"
        accept="image/*,video/*"
        className="sr-only"
        onChange={(e) => {
          const f = e.target.files?.[0]
          if (f) onReplace(f)
          e.target.value = ""
        }}
      />
    </div>
  )
}
